import AppKit
import Foundation
import PDFKit

let path = CommandLine.arguments.count > 1
    ? CommandLine.arguments[1]
    : ""
guard !path.isEmpty else {
    fputs("usage: pdf_render_smoke <path.pdf>\n", stderr)
    exit(2)
}
let url = URL(fileURLWithPath: path)
guard let doc = PDFDocument(url: url) else {
    fputs("PDFDocument load failed\n", stderr)
    exit(1)
}

let renderScale: CGFloat = 2.0
let maxPDFRenderPixelCount: CGFloat = 100_000_000

for pageIndex in [0, 1] {
    guard let page = doc.page(at: pageIndex) else {
        print("page \(pageIndex) missing")
        continue
    }
    let pageBounds = page.bounds(for: .cropBox)
    let rotation = page.rotation
    let pointSize: CGSize
    if rotation == 90 || rotation == 270 {
        pointSize = CGSize(width: pageBounds.height, height: pageBounds.width)
    } else {
        pointSize = pageBounds.size
    }
    let pointArea = pointSize.width * pointSize.height
    guard pointArea > 0 else {
        print("page \(pageIndex) pointArea 0")
        continue
    }
    let maxPixels = Double(maxPDFRenderPixelCount)
    let idealPixels = Double(pointArea) * Double(renderScale) * Double(renderScale)
    let effectiveScale: CGFloat
    if idealPixels <= maxPixels {
        effectiveScale = renderScale
    } else {
        effectiveScale = CGFloat(sqrt(maxPixels / Double(pointArea)))
    }
    let pixelSize = CGSize(
        width: pointSize.width * effectiveScale,
        height: pointSize.height * effectiveScale
    )
    let totalPixels = pixelSize.width * pixelSize.height
    let rep = NSBitmapImageRep(
        bitmapDataPlanes: nil,
        pixelsWide: Int(pixelSize.width),
        pixelsHigh: Int(pixelSize.height),
        bitsPerSample: 8,
        samplesPerPixel: 4,
        hasAlpha: true,
        isPlanar: false,
        colorSpaceName: .deviceRGB,
        bytesPerRow: 0,
        bitsPerPixel: 0
    )
    let ok = rep != nil
    print(
        "page \(pageIndex) point \(Int(pointSize.width))x\(Int(pointSize.height)) effectiveScale \(String(format: "%.4f", Double(effectiveScale))) pixel \(Int(pixelSize.width))x\(Int(pixelSize.height)) totalPixels \(Int(totalPixels)) bitmapOK \(ok)"
    )
}

